//! Spec-compliance tests: Run-level Formatting (ISO 29500-1 §17.3.2)
//!
//! These tests verify our implementation against specific OOXML run
//! formatting constructs.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{InlineNode, Mark, MarkValue};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/run-formatting";

// ── helpers ──────────────────────────────────────────────────────────────
fn text_nodes(p: &stemma::ParagraphNode) -> Vec<stemma::TextNode> {
    p.all_inlines_owned()
        .into_iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(*t),
            _ => None,
        })
        .collect()
}

// ── w:u (underline styles) ──────────────────────────────────────────────

/// ISO 29500-1 §17.3.2.40: Any underline style should produce Mark::Underline.
///
/// POSITIVE: The parser detects underline presence regardless of style variant.
#[test]
fn spec_underline_presence_detected() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "underline-styles");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let nodes = text_nodes(paras[0]);
    assert!(
        nodes.len() >= 5,
        "should have at least 5 text runs (one per underline style), got {}",
        nodes.len()
    );

    let styles = ["single", "double", "dotted", "dash", "wave"];
    for (i, style) in styles.iter().enumerate() {
        let node = &nodes[i];
        assert!(
            node.text.contains(style),
            "run {i} should contain '{style}', got '{}'",
            node.text
        );
        assert!(
            node.marks.contains(&Mark::Underline),
            "run with {style} underline should have Mark::Underline, \
             got marks: {:?} for text '{}'",
            node.marks,
            node.text
        );
    }
}

/// ISO 29500-1 §17.3.2.40: Underline styles should be distinguishable.
///
/// Underline styles are now exposed via style_props.underline_style.
#[test]
fn spec_underline_style_fidelity() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "underline-styles");

    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let single_run = nodes
        .iter()
        .find(|t| t.text.contains("single"))
        .expect("should have single-underline run");
    let double_run = nodes
        .iter()
        .find(|t| t.text.contains("double"))
        .expect("should have double-underline run");

    assert_eq!(
        single_run.style_props.underline_style,
        Some(stemma::domain::UnderlineStyle::Single),
        "single-underline run should have underline_style=Single, got {:?}",
        single_run.style_props.underline_style
    );
    assert_eq!(
        double_run.style_props.underline_style,
        Some(stemma::domain::UnderlineStyle::Double),
        "double-underline run should have underline_style=Double, got {:?}",
        double_run.style_props.underline_style
    );
    assert_ne!(
        single_run.style_props.underline_style, double_run.style_props.underline_style,
        "Single and double underline styles should be distinguishable"
    );
}

// ── w:strike / w:dstrike (strikethrough) ────────────────────────────────

/// ISO 29500-1 §17.3.2.37/9: strike and dstrike should be detected.
///
/// POSITIVE: The parser detects both strikethrough types.
/// w:strike → Mark::Strike, w:dstrike → Mark::DoubleStrike.
#[test]
fn spec_strikethrough_presence_detected() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "strikethrough-types");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let nodes = text_nodes(paras[0]);
    assert!(
        nodes.len() >= 2,
        "should have at least 2 text runs (single + double strike), got {}",
        nodes.len()
    );

    let single = nodes
        .iter()
        .find(|t| t.text.contains("single"))
        .expect("should have single-strike run");
    assert!(
        single.style_props.strike == MarkValue::On,
        "w:strike run should have strike=On, got style_props.strike: {:?}",
        single.style_props.strike
    );

    let double = nodes
        .iter()
        .find(|t| t.text.contains("double"))
        .expect("should have double-strike run");
    assert!(
        double.style_props.double_strike == MarkValue::On,
        "w:dstrike run should have double_strike=On, got style_props.double_strike: {:?}",
        double.style_props.double_strike
    );
}

/// ISO 29500-1 §17.3.2.37/9: Double-strike should be distinguishable from single.
///
/// POSITIVE: w:strike → Mark::Strike, w:dstrike → Mark::DoubleStrike.
#[test]
fn spec_strikethrough_type_fidelity() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "strikethrough-types");

    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let single = nodes
        .iter()
        .find(|t| t.text.contains("single"))
        .expect("should have single-strike run");
    let double = nodes
        .iter()
        .find(|t| t.text.contains("double"))
        .expect("should have double-strike run");

    // Single strike uses style_props.strike, double uses style_props.double_strike.
    assert!(
        single.style_props.strike == MarkValue::On
            && single.style_props.double_strike != MarkValue::On,
        "Single-strike run should have strike=On, double_strike!=On"
    );
    assert!(
        double.style_props.double_strike == MarkValue::On
            && double.style_props.strike != MarkValue::On,
        "Double-strike run should have double_strike=On, strike!=On"
    );
}

// ── w:rFonts (font slots) ───────────────────────────────────────────────

/// ISO 29500-1 §17.3.2.26: font_family should capture w:ascii/w:hAnsi.
///
/// POSITIVE: The parser captures font_family from the ascii/hAnsi slots.
#[test]
#[allow(non_snake_case)]
fn spec_font_ascii_hAnsi_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "font-slots");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let nodes = text_nodes(paras[0]);
    assert!(!nodes.is_empty(), "should have at least one text run");

    let node = &nodes[0];
    assert!(
        node.style_props.font_family.is_some(),
        "font_family should be parsed from w:rFonts ascii/hAnsi. \
         Got style_props: {:?} for text '{}'",
        node.style_props,
        node.text
    );
    assert_eq!(
        node.style_props.font_family.as_deref(),
        Some("Arial"),
        "font_family should be 'Arial' from w:ascii/w:hAnsi"
    );
}

/// ISO 29500-1 §17.3.2.26: eastAsia and cs font slots should be captured.
///
/// POSITIVE: font_east_asia and font_cs are now parsed from w:rFonts.
#[test]
#[allow(non_snake_case)]
fn spec_font_eastAsia_cs_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "font-slots");

    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);
    let node = &nodes[0];

    assert!(
        node.style_props.font_east_asia.is_some(),
        "font_east_asia should be parsed from w:rFonts w:eastAsia. \
         Got style_props: {:?}",
        node.style_props
    );
    assert_eq!(
        node.style_props.font_east_asia.as_deref(),
        Some("MS Mincho"),
        "font_east_asia should be 'MS Mincho'"
    );
    assert!(
        node.style_props.font_cs.is_some(),
        "font_cs should be parsed from w:rFonts w:cs. \
         Got style_props: {:?}",
        node.style_props
    );
    assert_eq!(
        node.style_props.font_cs.as_deref(),
        Some("Arial"),
        "font_cs should be 'Arial'"
    );
}

// ── text effects (emboss/imprint/outline/shadow) ────────────────────────

/// ISO 29500-1 §17.3.2.13/18/23/31: Text effects should be exposed as marks.
///
/// POSITIVE: Mark::Emboss, Mark::Imprint, Mark::Outline, Mark::Shadow are now parsed.
#[test]
fn spec_text_effects_emboss_imprint_outline_shadow() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "text-effects");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let nodes = text_nodes(paras[0]);
    assert!(
        nodes.len() >= 4,
        "should have at least 4 text runs (one per effect), got {}",
        nodes.len()
    );

    // Each text effect is now a tri-state MarkValue field on style_props.
    let check_effect = |label: &str, get_field: fn(&stemma::StyleProps) -> &MarkValue| {
        let node = nodes
            .iter()
            .find(|t| t.text.contains(label))
            .unwrap_or_else(|| panic!("should have {label}-text run"));
        assert_eq!(
            *get_field(&node.style_props),
            MarkValue::On,
            "{label} text effect should be On for run '{}'",
            node.text
        );
    };
    check_effect("emboss", |sp| &sp.emboss);
    check_effect("imprint", |sp| &sp.imprint);
    check_effect("outline", |sp| &sp.outline);
    check_effect("shadow", |sp| &sp.shadow);
}

// ── w:lang (language tags) ──────────────────────────────────────────────

/// ISO 29500-1 §17.3.2.20: Language tags should be accessible.
///
/// POSITIVE: lang and lang_east_asia are now parsed from w:lang.
#[test]
fn spec_language_tags_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "language-tags");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let nodes = text_nodes(paras[0]);
    assert!(
        nodes.len() >= 3,
        "should have at least 3 text runs (en-US, fr-FR, ja-JP), got {}",
        nodes.len()
    );

    let en_run = nodes
        .iter()
        .find(|t| t.text.contains("English"))
        .expect("should have English text run");
    assert_eq!(
        en_run.style_props.lang.as_deref(),
        Some("en-US"),
        "English run should have lang='en-US', got {:?}",
        en_run.style_props.lang
    );

    let fr_run = nodes
        .iter()
        .find(|t| t.text.contains("Texte"))
        .expect("should have French text run");
    assert_eq!(
        fr_run.style_props.lang.as_deref(),
        Some("fr-FR"),
        "French run should have lang='fr-FR', got {:?}",
        fr_run.style_props.lang
    );

    let ja_run = nodes
        .iter()
        .find(|t| t.text.contains("Japanese"))
        .expect("should have Japanese text run");
    assert_eq!(
        ja_run.style_props.lang_east_asia.as_deref(),
        Some("ja-JP"),
        "Japanese run should have lang_east_asia='ja-JP', got {:?}",
        ja_run.style_props.lang_east_asia
    );
}

// ── w:highlight (highlight colors) ──────────────────────────────────────

/// ISO 29500-1 §17.3.2.15: Highlight colors should be in style_props.highlight.
///
/// POSITIVE: The parser captures highlight color names.
#[test]
fn spec_highlight_colors_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "highlight-colors");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let nodes = text_nodes(paras[0]);
    assert!(
        nodes.len() >= 4,
        "should have at least 4 text runs (one per highlight color), got {}",
        nodes.len()
    );

    let expected_colors: &[(&str, stemma::domain::HighlightColor)] = &[
        ("yellow", stemma::domain::HighlightColor::Yellow),
        ("green", stemma::domain::HighlightColor::Green),
        ("cyan", stemma::domain::HighlightColor::Cyan),
        ("magenta", stemma::domain::HighlightColor::Magenta),
    ];
    for (name, color) in expected_colors {
        let node = nodes
            .iter()
            .find(|t| t.text.contains(name))
            .unwrap_or_else(|| panic!("should have {name}-highlight run"));

        assert_eq!(
            node.style_props.highlight,
            Some(color.clone()),
            "Run '{}' should have highlight={name}, got highlight={:?}",
            node.text,
            node.style_props.highlight
        );
    }
}

// ── w:caps / w:smallCaps ────────────────────────────────────────────────

/// ISO 29500-1 §17.3.2.5/33: Caps and SmallCaps marks should be parsed.
///
/// POSITIVE: The parser captures Mark::Caps and Mark::SmallCaps.
#[test]
fn spec_caps_smallcaps_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "caps-smallcaps");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let nodes = text_nodes(paras[0]);
    assert!(
        nodes.len() >= 2,
        "should have at least 2 text runs (caps + smallcaps), got {}",
        nodes.len()
    );

    let caps_run = nodes
        .iter()
        .find(|t| t.text.contains("all-caps"))
        .expect("should have all-caps run");
    assert!(
        caps_run.style_props.caps == MarkValue::On,
        "w:caps run should have caps=On, got style_props.caps: {:?} for text '{}'",
        caps_run.style_props.caps,
        caps_run.text
    );

    let sc_run = nodes
        .iter()
        .find(|t| t.text.contains("small-caps"))
        .expect("should have small-caps run");
    assert!(
        sc_run.style_props.small_caps == MarkValue::On,
        "w:smallCaps run should have small_caps=On, got style_props.small_caps: {:?} for text '{}'",
        sc_run.style_props.small_caps,
        sc_run.text
    );
}
